import React, { useState } from 'react';
import toast from 'react-hot-toast';

const NOTICES = [
  {title:'Parent-Teacher Meeting on 12 June 2025',type:'event',date:'Jun 5, 2025',by:'Principal'},
  {title:'Half-Yearly Exam Schedule Released',type:'circular',date:'Jun 3, 2025',by:'Academic Dept'},
  {title:'Annual Day Preparations Begin',type:'event',date:'Jun 1, 2025',by:'Event Committee'},
  {title:'School Closed on 15 June — Eid Holiday',type:'holiday',date:'Jun 7, 2025',by:'Admin'},
];

const TYPE_COLOR = {event:'#EDE9F8|#2D1B69',circular:'#DBEAFE|#1E40AF',holiday:'#D1FAE5|#065F46',urgent:'#FEE2E2|#991B1B',general:'#F3F4F6|#374151'};

export default function Notices() {
  const [showForm, setShowForm] = useState(false);
  const [form, setForm] = useState({title:'',content:'',type:'general'});

  return (
    <div>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:20}}>
        <div><h2 style={{fontSize:20,fontWeight:700}}>Notice Board</h2><p style={{fontSize:12,color:'#6B7280',marginTop:2}}>School notices and circulars</p></div>
        <button onClick={()=>setShowForm(true)} style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>📢 Post Notice</button>
      </div>

      <div style={{display:'flex',flexDirection:'column',gap:12}}>
        {NOTICES.map((n,i)=>{
          const [bg,c]=(TYPE_COLOR[n.type]||TYPE_COLOR.general).split('|');
          return (
            <div key={i} style={{background:'#fff',border:'0.5px solid #E5E7EB',borderRadius:12,padding:'16px 20px',display:'flex',alignItems:'flex-start',gap:14}}>
              <span style={{padding:'3px 10px',borderRadius:20,fontSize:10,fontWeight:700,background:bg,color:c,flexShrink:0,marginTop:2}}>{n.type.toUpperCase()}</span>
              <div style={{flex:1}}>
                <div style={{fontSize:13,fontWeight:600,color:'#111827'}}>{n.title}</div>
                <div style={{fontSize:11,color:'#9CA3AF',marginTop:4}}>Posted by {n.by} · {n.date}</div>
              </div>
            </div>
          );
        })}
      </div>

      {showForm && (
        <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.4)',zIndex:200,display:'flex',alignItems:'center',justifyContent:'center',padding:16}}>
          <div style={{background:'#fff',borderRadius:16,width:480,overflow:'hidden'}}>
            <div style={{padding:'16px 20px',borderBottom:'0.5px solid #E5E7EB',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
              <div style={{fontWeight:700,fontSize:15}}>📢 Post New Notice</div>
              <button onClick={()=>setShowForm(false)} style={{background:'#F3F4F6',border:'none',borderRadius:6,width:28,height:28,cursor:'pointer'}}>✕</button>
            </div>
            <div style={{padding:20}}>
              <div style={{marginBottom:12}}>
                <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',display:'block',marginBottom:5}}>Title *</label>
                <input value={form.title} onChange={e=>setForm({...form,title:e.target.value})} placeholder="Notice title…" style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none'}}/>
              </div>
              <div style={{marginBottom:12}}>
                <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',display:'block',marginBottom:5}}>Type</label>
                <select value={form.type} onChange={e=>setForm({...form,type:e.target.value})} style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none'}}>
                  {['general','circular','event','holiday','urgent'].map(t=><option key={t}>{t}</option>)}
                </select>
              </div>
              <div style={{marginBottom:16}}>
                <label style={{fontSize:11,fontWeight:700,color:'#4B5563',textTransform:'uppercase',display:'block',marginBottom:5}}>Content *</label>
                <textarea value={form.content} onChange={e=>setForm({...form,content:e.target.value})} rows={3} placeholder="Write the notice content…" style={{width:'100%',padding:'9px 12px',border:'1px solid #E5E7EB',borderRadius:8,fontSize:13,outline:'none',resize:'vertical'}}/>
              </div>
              <div style={{display:'flex',gap:10,justifyContent:'flex-end'}}>
                <button onClick={()=>setShowForm(false)} style={{padding:'8px 16px',border:'1px solid #E5E7EB',borderRadius:8,background:'#fff',fontSize:13,cursor:'pointer'}}>Cancel</button>
                <button onClick={()=>{toast.success('Notice published!');setShowForm(false);}} style={{padding:'8px 18px',background:'#2D1B69',color:'#fff',border:'none',borderRadius:8,fontSize:13,fontWeight:600,cursor:'pointer'}}>Publish</button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
